def xml_escape(s):
    return s.replace('&', '&amp;').replace('"', '&quot;').replace('<', '&lt;').replace('>', '&gt;')


def generate_mac_strings(translations):
    """Generate <MacStrings> XML block."""
    lines = ['\t\t\t<MacStrings>']
    for str_id, english in MISSING:
        text = translations.get(str_id, english)
        lines.append(f'\t\t\t\t<Item id="{str_id}" name="{xml_escape(text)}"/>')
    lines.append('\t\t\t</MacStrings>')
    return '\n'.join(lines)


def insert_into_xml(xml_path, lang_stem):
    """Insert <MacStrings> into a language XML file."""
    with open(xml_path, 'r', encoding='utf-8') as f:
        content = f.read()

    # Skip if already has MacStrings
    if '<MacStrings>' in content:
        return 'skipped (already has MacStrings)'

    # Use Russian translations for russian, English for everything else
    if lang_stem == 'russian':
        translations = RUSSIAN
    else:
        translations = {}  # Falls back to English

    mac_xml = generate_mac_strings(translations)

    # Insert before </Dialog>
    if '</Dialog>' in content:
        content = content.replace('</Dialog>', mac_xml + '\n\t\t</Dialog>', 1)
    elif '</Native-Langue>' in content:
        content = content.replace('</Native-Langue>',
            '\t\t<Dialog>\n' + mac_xml + '\n\t\t</Dialog>\n\t</Native-Langue>', 1)
    else:
        return 'FAILED (no insertion point)'

    with open(xml_path, 'w', encoding='utf-8') as f:
        f.write(content)
    return 'updated'


def main():
    if not os.path.isdir(LOC_DIR):
        print(f"Error: {LOC_DIR} not found")
        sys.exit(1)

    xml_files = sorted(f for f in os.listdir(LOC_DIR) if f.endswith('.xml'))
    print(f"Found {len(xml_files)} language files")
    print(f"Adding {len(MISSING)} missing macOS strings\n")

    for xml_file in xml_files:
        lang = os.path.splitext(xml_file)[0]
        path = os.path.join(LOC_DIR, xml_file)
        result = insert_into_xml(path, lang)
        label = "Russian" if lang == "russian" else "English fallback"
        print(f"  {xml_file}: {result} ({label})")

    print(f"\nDone. Russian has full translations. Other languages have English placeholders.")
    print("Community translators can update the <MacStrings> section in each language file.")


if __name__ == '__main__':
    main()
